export const pokemonData = [
  { id: 1, name: 'Bulbasaur', type: 'Planta/Veneno', height: '0.7 m', weight: '6.9 kg', ability: 'Espesura', description: 'Un Pokémon raro que nace con una semilla en el lomo. A medida que crece, la semilla absorbe nutrientes y se desarrolla en una planta que florece. Puede pasar días sin comer gracias a los nutrientes que almacena en el bulbo. Su caparazón verde con manchas es característico de esta especie.', category: 'Pokémon Semilla', habitat: 'Praderas y bosques', weaknesses: 'Fuego, Hielo, Volador, Psíquico' },
  { id: 2, name: 'Ivysaur', type: 'Planta/Veneno', height: '1.0 m', weight: '13.0 kg', ability: 'Espesura', description: 'Cuando la luz solar refuerza sus capacidades, el bulbo en su espalda florece y emite un dulce aroma. Este aroma atrae a otros Pokémon y es señal de que está cerca de evolucionar. La planta en su espalda crece según la luz solar que recibe.', category: 'Pokémon Semilla', habitat: 'Bosques soleados', weaknesses: 'Fuego, Hielo, Volador, Psíquico' },
  { id: 3, name: 'Venusaur', type: 'Planta/Veneno', height: '2.0 m', weight: '100.0 kg', ability: 'Espesura', description: 'La flor florece absorbiendo la energía solar. Puede convertir la luz en energía y liberar un aroma relajante. La flor en su espalda puede capturar rayos de sol y convertirlos en energía, liberando oxígeno puro cuando florece completamente.', category: 'Pokémon Semilla', habitat: 'Bosques profundos', weaknesses: 'Fuego, Hielo, Volador, Psíquico' },
  { id: 4, name: 'Charmander', type: 'Fuego', height: '0.6 m', weight: '8.5 kg', ability: 'Mar de llamas', description: 'La llama de su cola indica su estado emocional. Si la llama arde intensamente, está emocionado. Si la llama se apaga, el Pokémon se debilita. Nace de un huevo con la llama ya encendida en su cola.', category: 'Pokémon Lagarto', habitat: 'Montañas rocosas', weaknesses: 'Agua, Tierra, Roca' },
  { id: 5, name: 'Charmeleon', type: 'Fuego', height: '1.1 m', weight: '19.0 kg', ability: 'Mar de llamas', description: 'Ataca con sus garras afiladas y su cola llameante. Cuando lucha con enemigos difíciles, su cola arde con más intensidad. Tiene temperamento agresivo y siempre busca pelea.', category: 'Pokémon Llama', habitat: 'Montañas rocosas', weaknesses: 'Agua, Tierra, Roca' },
  { id: 6, name: 'Charizard', type: 'Fuego/Volador', height: '1.7 m', weight: '90.5 kg', ability: 'Mar de llamas', description: 'Puede derretir cualquier material con su aliento de fuego. Sus alas le permiten volar hasta 1400 metros de altura. Cuando exhala fuego, la temperatura puede llegar a 1400 grados Celsius.', category: 'Pokémon Llama', habitat: 'Montañas altas', weaknesses: 'Agua, Eléctrico, Roca' },
  { id: 7, name: 'Squirtle', type: 'Agua', height: '0.5 m', weight: '9.0 kg', ability: 'Torrente', description: 'Se esconde en su caparazón y se defiende disparando agua con precisión. El caparazón no solo lo protege, sino que también le da forma hidrodinámica para nadar más rápido. Cuando se siente amenazado, retrae sus patas en el caparazón.', category: 'Pokémon Tortuguita', habitat: 'Lagos y estanques', weaknesses: 'Eléctrico, Planta' },
  { id: 8, name: 'Wartortle', type: 'Agua', height: '1.0 m', weight: '22.5 kg', ability: 'Torrente', description: 'Su cola larga y peluda es un símbolo de longevidad. Es muy popular entre los entrenadores mayores. Usa sus orejas peludas como plumas al nadar para mantener el equilibrio. Ha desarrollado garras afiladas que usa para atacar y nadar con más fuerza.', category: 'Pokémon Tortuga', habitat: 'Aguas limpias', weaknesses: 'Eléctrico, Planta' },
  { id: 9, name: 'Blastoise', type: 'Agua', height: '1.6 m', weight: '85.5 kg', ability: 'Torrente', description: 'Dispara agua a alta presión por los cañones de su caparazón. La fuerza de sus chorros puede perforar acero. Los cañones en su espalda se han desarrollado a partir de su caparazón y pueden girar 360 grados.', category: 'Pokémon Acorazado', habitat: 'Lagos grandes', weaknesses: 'Eléctrico, Planta' },
  { id: 10, name: 'Caterpie', type: 'Bicho', height: '0.3 m', weight: '2.9 kg', ability: 'Polvo Escudo', description: 'Su corto cuerpo está cubierto de una piel blanda y verde. Se alimenta de hojas grandes y crece muy rápido durante esta etapa. De su frente sale un órgano que libera un olor fétido para repeler a los enemigos.', category: 'Pokémon Oruga', habitat: 'Bosques y praderas', weaknesses: 'Fuego, Volador, Roca' },
  { id: 11, name: 'Metapod', type: 'Bicho', height: '0.7 m', weight: '9.9 kg', ability: 'Mudar', description: 'Su cuerpo está duro como una concha de hierro mientras espera evolucionar. Es tan duro que ni siquiera una picadura de Pidgeotto puede dañarlo. Durante esta etapa, su cuerpo está reorganizando sus células.', category: 'Pokémon Capullo', habitat: 'Bosques y árboles', weaknesses: 'Fuego, Volador, Roca' },
  { id: 12, name: 'Butterfree', type: 'Bicho/Volador', height: '1.1 m', weight: '32.0 kg', ability: 'Ojo Compuesto', description: 'Sus alas están cubiertas de escamas venenosas que caen cuando vuela. Puede detectar el polen de flores a más de un kilómetro de distancia. Sus grandes alas le permiten volar largas distancias.', category: 'Pokémon Mariposa', habitat: 'Bosques florecientes', weaknesses: 'Fuego, Volador, Roca, Eléctrico, Hielo' },
  { id: 13, name: 'Weedle', type: 'Bicho/Veneno', height: '0.3 m', weight: '3.2 kg', ability: 'Polvo Escudo', description: 'Tiene un aguijón venenoso en la cabeza y en la cola. El veneno es muy potente y puede causar dolor intenso. Se alimenta de hojas y tiene un olfato muy desarrollado para encontrar sus hojas favoritas.', category: 'Pokémon Oruga', habitat: 'Bosques y praderas', weaknesses: 'Fuego, Volador, Roca, Psíquico' },
  { id: 14, name: 'Kakuna', type: 'Bicho/Veneno', height: '0.6 m', weight: '10.0 kg', ability: 'Mudar', description: 'Casi incapaz de moverse, solo endurece su caparazón mientras espera evolucionar. Puede mover ligeramente su aguijón para defenderse. En este estado, su cuerpo se está reorganizando para convertirse en Beedrill.', category: 'Pokémon Capullo', habitat: 'Bosques y árboles', weaknesses: 'Fuego, Volador, Roca, Psíquico' },
  { id: 15, name: 'Beedrill', type: 'Bicho/Veneno', height: '1.0 m', weight: '29.5 kg', ability: 'Enjambre', description: 'Tiene tres aguijones venenosos en sus patas y cola. Puede atacar con los tres simultáneamente y su veneno es extremadamente potente. Vuela a gran velocidad y ataca en grupo cuando se siente amenazado.', category: 'Pokémon Abeja Veneno', habitat: 'Bosques densos', weaknesses: 'Fuego, Volador, Roca, Psíquico' },
  { id: 16, name: 'Pidgey', type: 'Normal/Volador', height: '0.3 m', weight: '1.8 kg', ability: 'Vista Lince', description: 'Es manso y prefiere evitar el combate. Si se siente amenazado, levanta tierra con las alas para confundir al enemigo. Tiene un sentido de dirección increíble y nunca se pierde, sin importar qué tan lejos vuele.', category: 'Pokémon Pájaro Pequeño', habitat: 'Bosques y praderas', weaknesses: 'Eléctrico, Hielo, Roca' },
  { id: 17, name: 'Pidgeotto', type: 'Normal/Volador', height: '1.1 m', weight: '30.0 kg', ability: 'Vista Lince', description: 'Su excelente vista le permite ver presas a gran distancia, incluso desde más de 100 metros de altura. Es muy territorial y protege su nido ferozmente. Sus garras afiladas son letales.', category: 'Pokémon Pájaro', habitat: 'Bosques densos', weaknesses: 'Eléctrico, Hielo, Roca' },
  { id: 18, name: 'Pidgeot', type: 'Normal/Volador', height: '1.5 m', weight: '39.5 kg', ability: 'Vista Lince', description: 'Vuela a velocidades Mach 2 en busca de presas. Su plumaje es magnífico y ha sido codiciado durante siglos. Puede crear ráfagas de viento con sus alas que doblan árboles. Su cresta se eriza cuando está enfurecido.', category: 'Pokémon Pájaro', habitat: 'Bosques profundos', weaknesses: 'Eléctrico, Hielo, Roca' },
  { id: 19, name: 'Rattata', type: 'Normal', height: '0.3 m', weight: '3.5 kg', ability: 'Fuga', description: 'Sus colmillos crecen continuamente y debe roer cosas duras para mantenerlos afilados. Es muy adaptable y puede vivir en cualquier lugar donde haya comida. Se reproduce muy rápido y vive en grandes colonias.', category: 'Pokémon Ratón', habitat: 'Praderas, bosques y ciudades', weaknesses: 'Lucha' },
  { id: 20, name: 'Raticate', type: 'Normal', height: '0.7 m', weight: '18.5 kg', ability: 'Fuga', description: 'Sus patas traseras le permiten nadar por los ríos para cazar presas acuáticas. Sus colmillos son muy afilados y crecen constantemente. Es muy territorial y agresivo cuando se siente amenazado.', category: 'Pokémon Ratón', habitat: 'Cerca de agua y praderas', weaknesses: 'Lucha' },
  { id: 21, name: 'Spearow', type: 'Normal/Volador', height: '0.3 m', weight: '2.0 kg', ability: 'Vista Lince', description: 'Vuela a baja altitud y canta con voz aguda. Es muy territorial y ataca en grupo cuando se siente amenazado. Su vuelo es rápido pero no puede volar a gran altitud por períodos prolongados.', category: 'Pokémon Pájaro Pequeño', habitat: 'Praderas abiertas y campos', weaknesses: 'Eléctrico, Hielo, Roca' },
  { id: 22, name: 'Fearow', type: 'Normal/Volador', height: '1.2 m', weight: '38.0 kg', ability: 'Vista Lince', description: 'Su largo pico y cuello le dan una apariencia amenazante. Puede volar durante horas sin cansarse gracias a sus grandes alas. Su pico es una herramienta efectiva para cavar en busca de presas.', category: 'Pokémon Pico', habitat: 'Praderas y zonas abiertas', weaknesses: 'Eléctrico, Hielo, Roca' },
  { id: 23, name: 'Ekans', type: 'Veneno', height: '2.0 m', weight: '6.9 kg', ability: 'Intimidación', description: 'Se enroja en espiral para descansar. Puede detectar vibraciones en el suelo con su lengua bifurcada. Su veneno no es mortal pero causa dolor intenso e hinchazón.', category: 'Pokémon Serpiente', habitat: 'Praderas y zonas de pasto', weaknesses: 'Tierra, Psíquico' },
  { id: 24, name: 'Arbok', type: 'Veneno', height: '3.5 m', weight: '65.0 kg', ability: 'Intimidación', description: 'El patrón de su piel varía según la región. Puede aplastar cosas con su cuerpo poderoso. El diseño en su pecho asusta a sus enemigos y puede inmovilizar a presas más pequeñas con solo mirarlas.', category: 'Pokémon Cobra', habitat: 'Praderas y ruinas antiguas', weaknesses: 'Tierra, Psíquico' },
  { id: 25, name: 'Pikachu', type: 'Eléctrico', height: '0.4 m', weight: '6.0 kg', ability: 'Elec. Estática', description: 'Mantiene su cola en alto para vigilar los alrededores. Si amenazan, descarga potentes electricidades. Las bolsas en sus mejillas se llenan de electricidad y poco a poco se vuelven más amarillas. Es el Pokémon más popular del mundo.', category: 'Pokémon Ratón', habitat: 'Bosques y zonas eléctricas', weaknesses: 'Tierra' },
  { id: 26, name: 'Raichu', type: 'Eléctrico', height: '0.8 m', weight: '30.0 kg', ability: 'Elec. Estática', description: 'Su larga cola le permite descargar hasta 100,000 voltios. Cuando acumula demasiada electricidad, se vuelve agresivo. Puede utilizar su cola como toma de tierra para protegerse de su propia electricidad.', category: 'Pokémon Ratón', habitat: 'Zonas con electricidad', weaknesses: 'Tierra' },
  { id: 27, name: 'Sandshrew', type: 'Tierra', height: '0.6 m', weight: '12.0 kg', ability: 'Velo Arena', description: 'Se enroja para proteger su vientre blando. Sus garras afiladas le permiten excavar a gran velocidad. Se hidrata enrollándose en hierba húmeda durante la noche. Su piel es tan dura como la roca.', category: 'Pokémon Ratón', habitat: 'Desiertos y zonas áridas', weaknesses: 'Agua, Planta, Hielo' },
  { id: 28, name: 'Sandslash', type: 'Tierra', height: '1.0 m', weight: '29.5 kg', ability: 'Velo Arena', description: 'Sus garras son armas letales en combate. Sus espinas dorsales le ayudan a defenderse de depredadores. Es muy hábil cavando túneles y puede crear madrigueras complejas en poco tiempo.', category: 'Pokémon Ratón', habitat: 'Desiertos y tierras secas', weaknesses: 'Agua, Planta, Hielo' },
  { id: 29, name: 'Nidoran♀', type: 'Veneno', height: '0.4 m', weight: '7.0 kg', ability: 'Punto Tóxico', description: 'Sus pequeños cuernos secretan veneno. Tiene un olfato más desarrollado que los machos. Es capaz de detectar bayas deliciosas escondidas bajo tierra. Prefiere evitar el combate directo.', category: 'Pokémon Pin Veneno', habitat: 'Praderas y zonas de pasto', weaknesses: 'Tierra, Psíquico' },
  { id: 30, name: 'Nidorina', type: 'Veneno', height: '0.8 m', weight: '20.0 kg', ability: 'Punto Tóxico', description: 'Sus picos desarrollan veneno al evolucionar. Es más agresiva cuando protege a sus crías. Sus patas son fuertes y pueden lanzar ataques devastadores. Evita pelear cuando está sola.', category: 'Pokémon Pin Veneno', habitat: 'Praderas y zonas de pasto', weaknesses: 'Tierra, Psíquico' },
  { id: 31, name: 'Nidoqueen', type: 'Veneno/Tierra', height: '1.3 m', weight: '60.0 kg', ability: 'Punto Tóxico', description: 'Su dura piel protege al nido de los enemigos. Sus garras pueden destrozar rocas y diamantes. Es muy maternal y protege ferozmente a sus crías. Su cola es poderosa y puede derribar enemigos con un solo golpe.', category: 'Pokémon Taladro', habitat: 'Praderas y zonas de pasto', weaknesses: 'Tierra, Psíquico, Hielo, Agua' },
  { id: 32, name: 'Nidoran♂', type: 'Veneno', height: '0.5 m', weight: '9.0 kg', ability: 'Rivalidad', description: 'Sus cuernos son más grandes que los de la hembra. Son venenosos y secretan toxinas cuando se siente amenazado. Tiene un excelente sentido del olfato que usa para encontrar comida.', category: 'Pokémon Pin Veneno', habitat: 'Praderas y zonas de pasto', weaknesses: 'Tierra, Psíquico' },
  { id: 33, name: 'Nidorino', type: 'Veneno', height: '0.9 m', weight: '19.5 kg', ability: 'Rivalidad', description: 'Tiene un temperamento agresivo y nervioso. Sus cuernos son tan duros que pueden perforar rocas. Ataca con furia cuando se siente amenazado, lanzando golpes con sus púas venenosas.', category: 'Pokémon Pin Veneno', habitat: 'Praderas y zonas de pasto', weaknesses: 'Tierra, Psíquico' },
  { id: 34, name: 'Nidoking', type: 'Veneno/Tierra', height: '1.4 m', weight: '62.0 kg', ability: 'Rivalidad', description: 'Su cola es una herramienta destructiva que puede destrozar torres de acero. Su piel es tan dura que resiste ataques de lava. Es extremadamente territorial y protege su dominio ferozmente.', category: 'Pokémon Taladro', habitat: 'Praderas y zonas de pasto', weaknesses: 'Tierra, Psíquico, Hielo, Agua' },
  { id: 35, name: 'Clefairy', type: 'Hada', height: '0.6 m', weight: '7.5 kg', ability: 'Gran Encanto', description: 'Es tímido y raramente se muestra ante humanos. Su silueta se parece a la luna. Se dice que trae buena suerte a quienes lo ven. Baila en círculos bajo la luna llena.', category: 'Pokémon Hada', habitat: 'Montañas y zonas tranquilas', weaknesses: 'Acero, Veneno' },
  { id: 36, name: 'Clefable', type: 'Hada', height: '1.3 m', weight: '40.0 kg', ability: 'Gran Encanto', description: 'Sus grandes orejas le permiten oír desde lejos, incluso un alfiler caer a 1 km de distancia. Es muy tímido y huye al sentirse observado. Su cola es característica por su forma de espiral.', category: 'Pokémon Hada', habitat: 'Montañas y zonas tranquilas', weaknesses: 'Acero, Veneno' },
  { id: 37, name: 'Vulpix', type: 'Fuego', height: '0.6 m', weight: '9.9 kg', ability: 'Absorbe Fuego', description: 'Su cola se divide en seis cuando evoluciona. Su pelaje es muy valorado. Puede escupir fuego controlando la temperatura de su cuerpo. Las seis colas se calientan antes de lanzar llamaradas.', category: 'Pokémon Zorro', habitat: 'Praderas y zonas cálidas', weaknesses: 'Agua, Tierra, Roca' },
  { id: 38, name: 'Ninetales', type: 'Fuego', height: '1.1 m', weight: '19.9 kg', ability: 'Absorbe Fuego', description: 'Cuenta la leyenda que vive 1,000 años. Cada una de sus nueve colas tiene poderes místicos. Puede controlar fuego con precisión milimétrica. Su pelaje dorado brilla al atardecer.', category: 'Pokémon Zorro', habitat: 'Praderas y zonas sagradas', weaknesses: 'Agua, Tierra, Roca' },
  { id: 39, name: 'Jigglypuff', type: 'Normal/Hada', height: '0.5 m', weight: '5.5 kg', ability: 'Gran Encanto', description: 'Canta una canción de cuna que duerme a todos. Su cuerpo es elástico como un globo. Cuando se enoja, su cuerpo se infla hasta triplicar su tamaño. Tiene ojos grandes y expresivos.', category: 'Pokémon Globo', habitat: 'Praderas y zonas tranquilas', weaknesses: 'Acero, Veneno' },
  { id: 40, name: 'Wigglytuff', type: 'Normal/Hada', height: '1.0 m', weight: '12.0 kg', ability: 'Gran Encanto', description: 'Su piel es tan elástica que puede expandirse. Si se infla completamente, puede tener 10 metros de diámetro. Su pelaje es extremadamente suave. Puede cantonaras hipnóticas que duermen a todo el público.', category: 'Pokémon Globo', habitat: 'Praderas y zonas tranquilas', weaknesses: 'Acero, Veneno' },
  { id: 41, name: 'Zubat', type: 'Veneno/Volador', height: '0.8 m', weight: '7.5 kg', ability: 'Foco Interno', description: 'Vive en cuevas oscuras y sale de noche. Usa ultrasonidos para navegar en la oscuridad. Se cansa fácilmente durante el día y busca lugares oscuros para descansar. Sus colmillos son pequeños pero afilados.', category: 'Pokémon Murciélago', habitat: 'Cuevas oscuras', weaknesses: 'Eléctrico, Hielo, Psíquico, Roca' },
  { id: 42, name: 'Golbat', type: 'Veneno/Volador', height: '1.6 m', weight: '55.0 kg', ability: 'Foco Interno', description: 'Sus colmillos pueden perforar piel gruesa. Tiene sed de sangre constante y ataca sin piedad. Sus alas son poderosas y le permiten volar largas distancias sin cansarse. Es temido por otros Pokémon pequeños.', category: 'Pokémon Murciélago', habitat: 'Cuevas oscuras', weaknesses: 'Eléctrico, Hielo, Psíquico, Roca' },
  { id: 43, name: 'Oddish', type: 'Planta/Veneno', height: '0.5 m', weight: '5.4 kg', ability: 'Clorofila', description: 'Camina durante la noche y entierra sus raíces de día. Sus raíces absorben nutrientes del suelo mientras duerme. Prefiere lugares húmedos y oscuros. Las hojas en su cabeza son muy nutritivas.', category: 'Pokémon Hierba', habitat: 'Bosques y praderas húmedas', weaknesses: 'Fuego, Hielo, Volador, Psíquico' },
  { id: 44, name: 'Gloom', type: 'Planta/Veneno', height: '0.8 m', weight: '8.6 kg', ability: 'Clorofila', description: 'Huele tan mal que puede causar desmayos a 2 kilómetros de distancia. El líquido que gotea de su boca es extremadamente tóxico. A pesar del olor, algunos Pokémon se sienten atraídos por él. Prefiere lugares muy húmedos.', category: 'Pokémon Hierba', habitat: 'Bosques húmedos', weaknesses: 'Fuego, Hielo, Volador, Psíquico' },
  { id: 45, name: 'Vileplume', type: 'Planta/Veneno', height: '1.2 m', weight: '18.6 kg', ability: 'Clorofila', description: 'Su flor libera polen alergénico que causa estornudos constantes. La flor es muy pesada y apenas puede mantenerla erguida. Cuando camina, suelta nubes de polen tóxico. Es la evolución final de Oddish.', category: 'Pokémon Flor', habitat: 'Selvas tropicales', weaknesses: 'Fuego, Hielo, Volador, Psíquico' },
  { id: 46, name: 'Paras', type: 'Bicho/Planta', height: '0.3 m', weight: '5.4 kg', ability: 'Efecto Espora', description: 'Tiene hongos parásitos en su espalda llamados tochukaso. El hongo drena nutrientes del cuerpo de Paras. A medida que crece, el hongo crece más rápido que el insecto. Las esporas del hongo tienen propiedades medicinales.', category: 'Pokémon Hongo', habitat: 'Bosques oscuros', weaknesses: 'Fuego, Volador, Roca, Veneno, Bicho, Hielo' },
  { id: 47, name: 'Parasect', type: 'Bicho/Planta', height: '1.0 m', weight: '29.5 kg', ability: 'Efecto Espora', description: 'El hongo controla completamente su cuerpo. El insecto original está casi muerto, solo el hongo dirige sus movimientos. Libera esporas tóxicas para controlar a otros insectos. Es muy agresivo y ataca sin provocación.', category: 'Pokémon Hongo', habitat: 'Bosques oscuros y húmedos', weaknesses: 'Fuego, Volador, Roca, Veneno, Bicho, Hielo' },
  { id: 48, name: 'Venonat', type: 'Bicho/Veneno', height: '1.0 m', weight: '30.0 kg', ability: 'Ojo Compuesto', description: 'Sus grandes ojos actúan como radar en la oscuridad. Están cubiertos de pelos finos que detectan movimientos del aire. Se alimenta de pequeños insectos que atrae con su olor dulce. Es nocturno y duerme durante el día.', category: 'Pokémon Insecto', habitat: 'Bosques oscuros', weaknesses: 'Fuego, Volador, Roca, Psíquico' },
  { id: 49, name: 'Venomoth', type: 'Bicho/Veneno', height: '1.5 m', weight: '12.5 kg', ability: 'Polvo Escudo', description: 'Las escamas de sus alas son muy tóxicas y causan parálisis. Cuando vuela, esparce polvo venenoso por todas partes. Es nocturno y se alimenta de polvo de flores pequeñas. Es veloz y difícil de atrapar.', category: 'Pokémon Polilla Veneno', habitat: 'Bosques y praderas', weaknesses: 'Fuego, Volador, Roca, Psíquico' },
  { id: 50, name: 'Diglett', type: 'Tierra', height: '0.2 m', weight: '0.8 kg', ability: 'Trampa Arena', description: 'Excava túneles bajo tierra a gran velocidad. Nunca se le ha visto la parte inferior de su cuerpo. Su piel es muy sensible a la luz solar. Deja montículos de tierra donde pasa. Es muy territorial de su territorio subterráneo.', category: 'Pokémon Topo', habitat: 'Cuevas y túneles', weaknesses: 'Agua, Planta, Hielo' },
  { id: 51, name: 'Dugtrio', type: 'Tierra', height: '0.7 m', weight: '33.3 kg', ability: 'Trampa Arena', description: 'Tres Diglett que trabajan como equipo. Pueden excavar a 100 km/h. Su fuerza combinada puede derribar edificios pequeños. Son muy territoriales y protegen su territorio subterráneo ferozmente.', category: 'Pokémon Topo', habitat: 'Cuevas y túneles', weaknesses: 'Agua, Planta, Hielo' },
  { id: 52, name: 'Meowth', type: 'Normal', height: '0.4 m', weight: '4.2 kg', ability: 'Recogida', description: 'Ama las cosas brillantes y entrena de noche. Tiene un aro en la frente que es su símbolo característico. Puede caminar sobre sus patas traseras y hablar como humanos. Es muy astuto y leal a su entrenador.', category: 'Pokémon Gato Araña', habitat: 'Ciudades y zonas urbanas', weaknesses: 'Lucha' },
  { id: 53, name: 'Persian', type: 'Normal', height: '1.0 m', weight: '32.0 kg', ability: 'Flexibilidad', description: 'Su elegancia y grace lo hacen muy popular. Su aro en la frente le da un aire noble. Es muy veloz y sus garras pueden cortar como cuchillas. Prefiere la compañía de entrenadores sofisticados.', category: 'Pokémon Gato Fino', habitat: 'Ciudades y zonas urbanas', weaknesses: 'Lucha' },
  { id: 54, name: 'Psyduck', type: 'Agua', height: '0.8 m', weight: '19.6 kg', ability: 'Humedad', description: 'Sufre dolores de cabeza constantes que bloquean sus poderes psíquicos. Cuando el dolor es insoportable, libera explosiones de energía psíquica sin controlar. Se sostiene la cabeza para aliviar el dolor.', category: 'Pokémon Pato', habitat: 'Lagos y ríos', weaknesses: 'Eléctrico, Planta' },
  { id: 55, name: 'Golduck', type: 'Agua', height: '1.7 m', weight: '76.6 kg', ability: 'Nado Rápido', description: 'Nada elegantemente por lagos y ríos. Sus aletas son muy poderosas y le permiten nadar contra corrientes fuertes. Es extremadamente inteligente y puede comunicarse telepáticamente. Sus poderes psíquicos son muy desarrollados.', category: 'Pokémon Pato', habitat: 'Lagos y ríos', weaknesses: 'Eléctrico, Planta' },
  { id: 56, name: 'Mankey', type: 'Lucha', height: '0.5 m', weight: '28.0 kg', ability: 'Espíritu Vital', description: 'Se enoja fácilmente y ataca sin pensar. Vive en grupos en las copas de los árboles. Su temperamento explosivo lo hace difícil de entrenar. Cuando se enfurece, su pulso se acelera y se vuelve más fuerte.', category: 'Pokémon Mono Cerdo', habitat: 'Bosques y selvas', weaknesses: 'Volador, Psíquico, Hada' },
  { id: 57, name: 'Primeape', type: 'Lucha', height: '1.0 m', weight: '32.0 kg', ability: 'Espíritu Vital', description: 'Nunca se calma una vez que se enfurece. Perseguirá a su enemigo hasta el fin del mundo. Su cuerpo está cubierto de vello que se eriza cuando está furioso. Puede correr durante días sin descansar.', category: 'Pokémon Mono Cerdo', habitat: 'Bosques y montañas', weaknesses: 'Volador, Psíquico, Hada' },
  { id: 58, name: 'Growlithe', type: 'Fuego', height: '0.7 m', weight: '19.0 kg', ability: 'Intimidación', description: 'Leal y valiente, protege a su entrenador con su vida. Tiene un sentido del olfato extraordinario que usa para rastrear. Es muy amigable con quienes confía, pero feroz con extraños. Su pelaje es suave y cálido.', category: 'Pokémon Cachorro', habitat: 'Praderas y zonas cercanas a volcanes', weaknesses: 'Agua, Tierra, Roca' },
  { id: 59, name: 'Arcanine', type: 'Fuego', height: '1.9 m', weight: '155.0 kg', ability: 'Intimidación', description: 'Legendario por su velocidad y gracia. Puede correr 10,000 km en 24 horas. Su pelaje dorado brilla al sol. Es muy noble y solo obedece a entrenadores dignos. Su rugido puede asustar a cualquier enemigo.', category: 'Pokémon Legendario', habitat: 'Praderas y montañas sagradas', weaknesses: 'Agua, Tierra, Roca' },
  { id: 60, name: 'Poliwag', type: 'Agua', height: '0.6 m', weight: '12.4 kg', ability: 'Humedad', description: 'Su piel es tan transparente que se ven sus órganos en espiral. La espiral gira cuando nada. No puede caminar bien en tierra firme. Su cola es su principal medio de propulsión en el agua.', category: 'Pokémon Renacuajo', habitat: 'Lagos y estanques', weaknesses: 'Eléctrico, Planta' },
  { id: 61, name: 'Poliwhirl', type: 'Agua', height: '1.0 m', weight: '20.0 kg', ability: 'Humedad', description: 'Los espirales de su vientre causan hipnosis profunda. Puede vivir dentro y fuera del agua. Cuando está en tierra, usa las burbujas en su estómago para respirar. Es muy ágil en el agua.', category: 'Pokémon Renacuajo', habitat: 'Lagos y estanques', weaknesses: 'Eléctrico, Planta' },
  { id: 62, name: 'Poliwrath', type: 'Agua/Lucha', height: '1.3 m', weight: '54.0 kg', ability: 'Absorbe Agua', description: 'Nada con fuerza gracias a sus músculos desarrollados. Puede nadar sin descanso durante dos días. Su cuerpo está lleno de músculos poderosos. Es capaz de cruzar océanos enteros nadando.', category: 'Pokémon Renacuajo', habitat: 'Lagos y océanos', weaknesses: 'Eléctrico, Planta' },
  { id: 63, name: 'Abra', type: 'Psíquico', height: '0.9 m', weight: '19.5 kg', ability: 'Foco Interno', description: 'Duerme 18 horas al día para usar telequinesis. Puede teletransportarse para escapar del peligro. Incluso dormido, siente el peligro y se teletransporta. Sus poderes psíquicos son inmensos.', category: 'Pokémon Psi', habitat: 'Zonas urbanas y campos', weaknesses: 'Bicho, Fantasma, Siniestro' },
  { id: 64, name: 'Kadabra', type: 'Psíquico', height: '1.3 m', weight: '56.5 kg', ability: 'Foco Interno', description: 'Emite ondas alfa que causan dolores de cabeza. Su cuchara emite ondas alfa que amplifican sus poderes. Puede doblar cucharas con la mente. Es muy inteligente y tiene un coeficiente intelectual de 5000.', category: 'Pokémon Psi', habitat: 'Zonas urbanas y campos', weaknesses: 'Bicho, Fantasma, Siniestro' },
  { id: 65, name: 'Alakazam', type: 'Psíquico', height: '1.5 m', weight: '48.0 kg', ability: 'Foco Interno', description: 'Su cerebro crece continuamente hasta la muerte. Tiene un coeficiente intelectual de 5000. Sus dos cucharas amplifican sus ondas cerebrales. Puede recordar todo lo que ha ocurrido desde su nacimiento.', category: 'Pokémon Psi', habitat: 'Zonas urbanas y campos', weaknesses: 'Bicho, Fantasma, Siniestro' },
  { id: 66, name: 'Machop', type: 'Lucha', height: '0.8 m', weight: '19.5 kg', ability: 'Agallas', description: 'Su cuerpo musculoso le da gran fuerza. Levanta pesas de Geodude para entrenar. Puede lanzar 100 puñetazos en un segundo. Sus músculos nunca se atrofian, incluso si no entrena.', category: 'Pokémon Superpoder', habitat: 'Montañas y cuevas', weaknesses: 'Volador, Psíquico, Hada' },
  { id: 67, name: 'Machoke', type: 'Lucha', height: '1.5 m', weight: '70.5 kg', ability: 'Agallas', description: 'Lleva un cinturón para controlar su fuerza. Su cuerpo está lleno de músculos poderosos. Puede levantar montañas con una sola mano. Ayuda a la gente con trabajos de fuerza.', category: 'Pokémon Superpoder', habitat: 'Montañas y cuevas', weaknesses: 'Volador, Psíquico, Hada' },
  { id: 68, name: 'Machamp', type: 'Lucha', height: '1.6 m', weight: '130.0 kg', ability: 'Agallas', description: 'Sus cuatro brazos pueden lanzar golpes imparables. Puede lanzar 1000 puñetazos en 2 segundos. Un solo golpe suyo puede mandar volando a un rival. Es el maestro de las artes marciales.', category: 'Pokémon Superpoder', habitat: 'Montañas y cuevas', weaknesses: 'Volador, Psíquico, Hada' },
  { id: 69, name: 'Bellsprout', type: 'Planta/Veneno', height: '0.7 m', weight: '4.0 kg', ability: 'Clorofila', description: 'Se mueve con rapidez para atrapar presas. Su cuerpo es extremadamente flexible y se dobla fácilmente. Usa su tallo como un látigo. Prefiere climas cálidos y húmedos.', category: 'Pokémon Flor', habitat: 'Selvas y bosques húmedos', weaknesses: 'Fuego, Hielo, Volador, Psíquico' },
  { id: 70, name: 'Weepinbell', type: 'Planta/Veneno', height: '1.0 m', weight: '6.4 kg', ability: 'Clorofila', description: 'Escupe polvo que paraliza a sus enemigos. Puede engullir presas grandes enteras. Duerme colgando de ramas por sus ganchos. La hoja de su cabeza actúa como sensor de movimiento.', category: 'Pokémon Matamoscas', habitat: 'Selvas y bosques húmedos', weaknesses: 'Fuego, Hielo, Volador, Psíquico' },
  { id: 71, name: 'Victreebel', type: 'Planta/Veneno', height: '1.7 m', weight: '15.5 kg', ability: 'Clorofila', description: 'Atrae presas con dulce aroma y las atrapa en su jarra digestive. Puede engullir presas grandes en segundos. El líquido en su interior es extremadamente ácido. Prefiere climas húmedos y tropicales.', category: 'Pokémon Matamoscas', habitat: 'Selvas tropicales', weaknesses: 'Fuego, Hielo, Volador, Psíquico' },
  { id: 72, name: 'Tentacool', type: 'Agua/Veneno', height: '0.9 m', weight: '45.5 kg', ability: 'Cuerpo Puro', description: 'Flota en el océano y usa tentáculos venenosos para defenderse. Sus tentáculos pueden regenerarse si se cortan. Es transparente y difícil de ver en el agua. Su veneno causa dolor intenso.', category: 'Pokémon Medusa', habitat: 'Océanos y mares', weaknesses: 'Eléctrico, Psíquico, Tierra' },
  { id: 73, name: 'Tentacruel', type: 'Agua/Veneno', height: '1.6 m', weight: '55.0 kg', ability: 'Cuerpo Puro', description: 'Sus 80 tentáculos pueden extenderse largamente para atrapar presas. Puede nadar a 30 nudos. Es muy territorial y protege su territorio del mar ferozmente. Sus tentáculos son extremadamente venenosos.', category: 'Pokémon Medusa', habitat: 'Océanos profundos', weaknesses: 'Eléctrico, Psíquico, Tierra' },
  { id: 74, name: 'Geodude', type: 'Roca/Tierra', height: '0.4 m', weight: '20.0 kg', ability: 'Cabeza Roca', description: 'Flota usando energía electromagnética. Su cuerpo es casi indestructible. Puede camuflarse perfectamente como una roca. Si se molesta, explota en cólera y ataca sin piedad.', category: 'Pokémon Roca', habitat: 'Montañas y cuevas', weaknesses: 'Agua, Planta, Hielo, Lucha, Tierra, Acero' },
  { id: 75, name: 'Graveler', type: 'Roca/Tierra', height: '1.0 m', weight: '105.0 kg', ability: 'Cabeza Roca', description: 'Le gusta rodar montaña abajo a gran velocidad. Puede explotar en pedazos si choca fuerte. Su piel es tan dura que resiste explosiones. Prefiere caminos empinados para rodar.', category: 'Pokémon Roca', habitat: 'Montañas y cuevas', weaknesses: 'Agua, Planta, Hielo, Lucha, Tierra, Acero' },
  { id: 76, name: 'Golem', type: 'Roca/Tierra', height: '1.4 m', weight: '300.0 kg', ability: 'Cabeza Roca', description: 'Su cuerpo es una roca viva inmensamente dura. Puede sobrevivir explosiones de dinamita. Si se parte en pedazos, puede reconstruirse solo. Es muy territorial y protector de su hogar.', category: 'Pokémon Megaton', habitat: 'Montañas y cuevas profundas', weaknesses: 'Agua, Planta, Hielo, Lucha, Tierra, Acero' },
  { id: 77, name: 'Ponyta', type: 'Fuego', height: '1.0 m', weight: '30.0 kg', ability: 'Fuga', description: 'Sus patas se fortalecen corriendo por terrenos duros. Su crin arde constantemente. Puede saltar edificios altos de un solo brinco. Es muy veloz y puede alcanzar gran velocidad en segundos.', category: 'Pokémon Caballo Fuego', habitat: 'Praderas y campos abiertos', weaknesses: 'Agua, Tierra, Roca' },
  { id: 78, name: 'Rapidash', type: 'Fuego', height: '1.7 m', weight: '95.0 kg', ability: 'Fuga', description: 'Galopa a 240 km/h con una melena ardiente. Solo se detiene cuando encuentra un rival más veloz. Su crin llamea intensamente cuando corre. Puede correr sobre el agua por fracciones de segundo.', category: 'Pokémon Caballo Fuego', habitat: 'Praderas y campos abiertos', weaknesses: 'Agua, Tierra, Roca' },
  { id: 79, name: 'Slowpoke', type: 'Agua/Psíquico', height: '1.2 m', weight: '36.0 kg', ability: 'Ritmo Propio', description: 'Tan lento que no siente dolor por un día. Pesca con su cola pero olvida qué está haciendo. Su cola se desprende fácilmente pero crece de nuevo. Es muy relajado y nunca se apura.', category: 'Pokémon Atontado', habitat: 'Lagos y ríos tranquilos', weaknesses: 'Eléctrico, Planta, Bicho, Siniestro, Fantasma' },
  { id: 80, name: 'Slowbro', type: 'Agua/Psíquico', height: '1.6 m', weight: '78.5 kg', ability: 'Ritmo Propio', description: 'Shellder mordió su cola y le dio poderes psíquicos. La mordedura de Shellder no le causa dolor. Juntos forman una simbiosis perfecta. Es mucho más inteligente que Slowpoke.', category: 'Pokémon Ermitaño', habitat: 'Lagos y playas', weaknesses: 'Eléctrico, Planta, Bicho, Siniestro, Fantasma' },
  { id: 81, name: 'Magnemite', type: 'Eléctrico/Acero', height: '0.3 m', weight: '6.0 kg', ability: 'Imán', description: 'Flota emitiendo ondas electromagnéticas. Genera electricidad de manera constante. Su cuerpo es metálico y resiste ataques magnéticos. Se alimenta de electricidad de fuentes cercanas.', category: 'Pokémon Imán', habitat: 'Fábricas y zonas industriales', weaknesses: 'Fuego, Lucha, Tierra' },
  { id: 82, name: 'Magneton', type: 'Eléctrico/Acero', height: '1.0 m', weight: '60.0 kg', ability: 'Imán', description: 'Tres Magnemite unidos que emiten ondas de radio. Puede generar campos magnéticos muy fuertes. Su presencia afecta a los aparatos electrónicos cercanos. Es muy territorial en zonas industriales.', category: 'Pokémon Imán', habitat: 'Fábricas y zonas industriales', weaknesses: 'Fuego, Lucha, Tierra' },
  { id: 83, name: 'Farfetch\'d', type: 'Normal/Volador', height: '0.8 m', weight: '15.0 kg', ability: 'Foco Interno', description: 'Nunca viaja sin su puerro/espada característica. Usa el puerro como arma para atacar y defenderse. Es valiente y noble. Su puerro le da fuerza y determinación en combate.', category: 'Pokémon Puerro', habitat: 'Praderas y zonas verdes', weaknesses: 'Eléctrico, Hielo, Roca' },
  { id: 84, name: 'Doduo', type: 'Normal/Volador', height: '1.4 m', weight: '39.2 kg', ability: 'Fuga', description: 'Sus dos cabezas piensan exactamente igual pero tienen personalidades diferentes. Puede correr a 60 km/h. Sus alas son pequeñas y no le permiten volar bien. Es muy territorial.', category: 'Pokémon Ave Gemela', habitat: 'Praderas y zonas abiertas', weaknesses: 'Eléctrico, Hielo, Roca' },
  { id: 85, name: 'Dodrio', type: 'Normal/Volador', height: '1.8 m', weight: '85.2 kg', ability: 'Fuga', description: 'Tres cabezas representan alegría, ira y tristeza. Puede correr a 80 km/h sin cansarse. Sus patas son poderosas y pueden dar patadas devastadoras. Es muy protector de su territorio.', category: 'Pokémon Ave Triple', habitat: 'Praderas y zonas abiertas', weaknesses: 'Eléctrico, Hielo, Roca' },
  { id: 86, name: 'Seel', type: 'Agua', height: '1.1 m', weight: '90.0 kg', ability: 'Sebo', description: 'Le encanta el frío polar y duerme sobre hielo. Su pelaje blanco es muy denso y le protege del frío. Puede romper hielo grueso con su cabeza. Nada con gracia en aguas heladas.', category: 'Pokémon León Marino', habitat: 'Mares helados y zonas polares', weaknesses: 'Eléctrico, Planta' },
  { id: 87, name: 'Dewgong', type: 'Agua/Hielo', height: '1.7 m', weight: '120.0 kg', ability: 'Sebo', description: 'Su cuerpo blanco es hermoso contra el hielo. Puede nadar a 15 nudos en aguas frías. Su pelaje es impermeable y térmico. Duerme durante el día y caza por la noche.', category: 'Pokémon León Marino', habitat: 'Mares helados y zonas polares', weaknesses: 'Eléctrico, Planta, Lucha' },
  { id: 88, name: 'Grimer', type: 'Veneno', height: '0.9 m', weight: '30.0 kg', ability: 'Hedor', description: 'Nace de lodo tóxico en fábricas abandonadas. Se alimenta de residuos industriales. Su cuerpo es viscoso y puede atravesar espacios pequeños. Deja un rastro tóxico donde pasa.', category: 'Pokémon Lodo', habitat: 'Fábricas y zonas industriales', weaknesses: 'Tierra, Psíquico' },
  { id: 89, name: 'Muk', type: 'Veneno', height: '1.2 m', weight: '30.0 kg', ability: 'Hedor', description: 'Su cuerpo hedionoso puede hacer llorar a cualquiera. Es tan tóxico que el suelo donde pasa se vuelve infértil por años. Puede crecer hasta triplicar su tamaño. Es muy peligroso para el medio ambiente.', category: 'Pokémon Lodo', habitat: 'Fábricas y zonas industriales', weaknesses: 'Tierra, Psíquico' },
  { id: 90, name: 'Shellder', type: 'Agua', height: '0.3 m', weight: '4.0 kg', ability: 'Caparazón', description: 'Su duro caparazón repele cualquier ataque. Puede cerrar su caparazón herméticamente para protegerse. Se alimenta de plancton filtrando agua. Si se abre, revela su cuerpo blando.', category: 'Pokémon Bivalvo', habitat: 'Costas rocosas y playas', weaknesses: 'Eléctrico, Planta' },
  { id: 91, name: 'Cloyster', type: 'Agua/Hielo', height: '1.5 m', weight: '132.5 kg', ability: 'Caparazón', description: 'Su caparazón es más duro que el diamante. Puede disparar espinas como proyectiles a alta velocidad. Su cuerpo está protegido por capas de concha impenetrables. Cierra su caparazón herméticamente para protegerse.', category: 'Pokémon Bivalvo', habitat: 'Costas rocosas y mares fríos', weaknesses: 'Eléctrico, Planta, Lucha' },
  { id: 92, name: 'Gastly', type: 'Fantasma/Veneno', height: '1.3 m', weight: '0.1 kg', ability: 'Levitación', description: 'Gas venenoso que puede volverse invisible. Tiene 95% de su cuerpo compuesto de gas tóxico. Puede envolver a sus enemigos y causar desmayos. Es más activo durante la noche.', category: 'Pokémon Gas', habitat: 'Cementerios y lugares oscuros', weaknesses: 'Fantasma, Siniestro, Psíquico, Tierra' },
  { id: 93, name: 'Haunter', type: 'Fantasma/Veneno', height: '1.6 m', weight: '0.1 kg', ability: 'Levitación', description: 'Toca a sus víctimas para robarles la vida. Puede atravesar paredes sólidas. Sus manos etéreas pueden tocar objetos físicos. Se alimenta de la energía vital de otros seres.', category: 'Pokémon Gas', habitat: 'Cementerios y lugares oscuros', weaknesses: 'Fantasma, Siniestro, Psíquico, Tierra' },
  { id: 94, name: 'Gengar', type: 'Fantasma/Veneno', height: '1.5 m', weight: '40.5 kg', ability: 'Levitación', description: 'Se esconde en las sombras para atacar. Puede absorber el calor corporal de sus víctimas. Es muy travieso y le gusta asustar a la gente. Su risa retumba en la oscuridad.', category: 'Pokémon Sombra', habitat: 'Cementerios y lugares oscuros', weaknesses: 'Fantasma, Siniestro, Psíquico, Tierra' },
  { id: 95, name: 'Onix', type: 'Roca/Tierra', height: '8.8 m', weight: '210.0 kg', ability: 'Cabeza Roca', description: 'Serpiente de roca que excava túneles subterráneos. Puede cavar a 80 km/h bajo tierra. Su cuerpo es más duro que el acero. Tembla cuando está agitado o enfurecido.', category: 'Pokémon Serpiente Roca', habitat: 'Cuevas y montañas', weaknesses: 'Agua, Planta, Hielo, Lucha, Tierra, Acero' },
  { id: 96, name: 'Drowzee', type: 'Psíquico', height: '1.0 m', weight: '32.4 kg', ability: 'Foco Interno', description: 'Come sueños de humanos y Pokémon durmiendo. Prefiere los sueños de niños pequeños. Su trompa actúa como un detector de sueños. Es muy pacífico y no ataca a menos que se sienta amenazado.', category: 'Pokémon Hipnosis', habitat: 'Praderas y zonas tranquilas', weaknesses: 'Bicho, Fantasma, Siniestro' },
  { id: 97, name: 'Hypno', type: 'Psíquico', height: '1.6 m', weight: '76.6 kg', ability: 'Foco Interno', description: 'Su péndulo hipnotiza a quien lo mira. Puede controlar la mente de otros con ondas psíquicas. Se dice que ha secuestrado a niños que miraron su péndulo. Es extremadamente peligroso.', category: 'Pokémon Hipnosis', habitat: 'Praderas y zonas tranquilas', weaknesses: 'Bicho, Fantasma, Siniestro' },
  { id: 98, name: 'Krabby', type: 'Agua', height: '0.4 m', weight: '6.5 kg', ability: 'Caparazón', description: 'Sus pinzas son armas poderosas pero se desprenden fácilmente. Vive cerca del agua y cava madrigueras en la arena. Es territorial y pelea por su territorio. Sus pinzas regeneran rápidamente.', category: 'Pokémon Cangrejo', habitat: 'Playas y costas rocosas', weaknesses: 'Eléctrico, Planta' },
  { id: 99, name: 'Kingler', type: 'Agua', height: '1.3 m', weight: '60.0 kg', ability: 'Corte Fuerte', description: 'Una pinza crece enormemente y tiene 10,000 HP de fuerza. Puede destrozar rocas con su pinza gigante. Su pinza más pequeña es más precisa para manejar objetos. Es muy territorial.', category: 'Pokémon Pinza', habitat: 'Playas y costas rocosas', weaknesses: 'Eléctrico, Planta' },
  { id: 100, name: 'Voltorb', type: 'Eléctrico', height: '0.5 m', weight: '10.4 kg', ability: 'Elec. Estática', description: 'Se dice que es una Poké Ball que cobró vida. Explota al menor estímulo. Su cuerpo es redondo y liso como una Poké Ball. Es difícil distinguirlo de una Poké Ball real.', category: 'Pokémon Bola', habitat: 'Fábricas y centrales eléctricas', weaknesses: 'Tierra' },
  { id: 101, name: 'Electrode', type: 'Eléctrico', height: '1.2 m', weight: '66.6 kg', ability: 'Elec. Estática', description: 'Explota con el más mínimo estímulo. Se dice que es una Poké Ball que cobró vida. Su cuerpo es muy sensible a la electricidad estática. Puede explotar con solo un toque, liberando energía masiva.', category: 'Pokémon Bola', habitat: 'Fábricas y centrales eléctricas', weaknesses: 'Tierra' },
  { id: 102, name: 'Exeggcute', type: 'Planta/Psíquico', height: '0.4 m', weight: '2.5 kg', ability: 'Clorofila', description: 'Seis huevos que usan telepatía para comunicarse. Están conectados telepáticamente y piensan como uno solo. Si uno se separa, busca reunirse con los demás inmediatamente. Su cáscara es muy dura.', category: 'Pokémon Huevo', habitat: 'Bosques y praderas', weaknesses: 'Fuego, Hielo, Veneno, Volador, Bicho, Fantasma, Siniestro' },
  { id: 103, name: 'Exeggutor', type: 'Planta/Psíquico', height: '2.0 m', weight: '120.0 kg', ability: 'Clorofila', description: 'Sus tres cabezas piensan independientemente. Cada cabeza tiene su propia personalidad. Sus cabezas pueden lanzar poderosos ataques psíquicos. Es originario de las islas tropicales.', category: 'Pokémon Coco', habitat: 'Selvas tropicales', weaknesses: 'Fuego, Hielo, Veneno, Volador, Bicho, Fantasma, Siniestro' },
  { id: 104, name: 'Cubone', type: 'Tierra', height: '0.4 m', weight: '6.5 kg', ability: 'Cabeza Roca', description: 'Llora por su madre muerta y lleva su calavera. La calavera le da protección y confianza. Es tímido y evita pelear, pero se vuelve valiente cuando protege a otros. Su llanto resuena en la noche.', category: 'Pokémon Solitario', habitat: 'Montañas y cuevas', weaknesses: 'Agua, Planta, Hielo' },
  { id: 105, name: 'Marowak', type: 'Tierra', height: '1.0 m', weight: '45.0 kg', ability: 'Cabeza Roca', description: 'Ha superado su tristeza y es un luchador feroz. Su hueso es un arma letal. Ha dominado el uso de su calavera como arma. Es protector de su territorio y crías.', category: 'Pokémon Apaleador', habitat: 'Montañas y cuevas', weaknesses: 'Agua, Planta, Hielo' },
  { id: 106, name: 'Hitmonlee', type: 'Lucha', height: '1.5 m', weight: '49.8 kg', ability: 'Flexibilidad', description: 'Sus piernas se estiran para dar patadas a distancia. Sus piernas son como resortes que pueden estirarse. Puede dar patadas circulares devastadoras. Es un maestro de artes marciales especializado en patadas.', category: 'Pokémon Patada', habitat: 'Ciudades y zonas de entrenamiento', weaknesses: 'Volador, Psíquico, Hada' },
  { id: 107, name: 'Hitmonchan', type: 'Lucha', height: '1.4 m', weight: '50.2 kg', ability: 'Puño Férreo', description: 'Sus puñetazos son tan rápidos que no se ven. Puede dar puñetazos perforantes como balas. Es un maestro de artes marciales especializado en puñetazos. Sus guantes protegen sus puños.', category: 'Pokémon Puñetazo', habitat: 'Ciudades y zonas de entrenamiento', weaknesses: 'Volador, Psíquico, Hada' },
  { id: 108, name: 'Lickitung', type: 'Normal', height: '1.2 m', weight: '65.5 kg', ability: 'Sebo', description: 'Su lengua de 2 metros puede paralizar con su saliva. Todo lo que lame queda baboso. Su lengua es más resistente de lo que parece. Se alimenta de cosas pegajosas y dulces.', category: 'Pokémon Lame', habitat: 'Bosques y praderas', weaknesses: 'Lucha' },
  { id: 109, name: 'Koffing', type: 'Veneno', height: '0.6 m', weight: '1.0 kg', ability: 'Levitación', description: 'Infla su cuerpo tóxico hasta casi explotar. Se alimenta de gases del subsuelo. Su cuerpo es más ligero que el aire. Prefiere lugares contaminados donde los gases son abundantes.', category: 'Pokémon Gas Venenoso', habitat: 'Fábricas y zonas industriales', weaknesses: 'Tierra, Psíquico' },
  { id: 110, name: 'Weezing', type: 'Veneno', height: '1.2 m', weight: '9.5 kg', ability: 'Levitación', description: 'Dos Koffing que se fusionaron por gases tóxicos. Crea gases venenosos más potentes que un solo Koffing. Sus gases pueden derrotar a enemigos grandes. Es muy común en fábricas abandonadas.', category: 'Pokémon Gas Venenoso', habitat: 'Fábricas y zonas industriales', weaknesses: 'Tierra, Psíquico' },
  { id: 111, name: 'Rhyhorn', type: 'Tierra/Roca', height: '1.0 m', weight: '115.0 kg', ability: 'Cabeza Roca', description: 'Su cuerpo está protegido por piel de roca. Tiene un cerebro muy pequeño y se estrella contra cosas al olvidar detenerse. Sus patas son cortas y poderosas. Puede derribar edificios con su carga.', category: 'Pokémon Clavos', habitat: 'Montañas y terrenos rocosos', weaknesses: 'Agua, Planta, Hielo, Lucha, Tierra, Acero' },
  { id: 112, name: 'Rhydon', type: 'Tierra/Roca', height: '1.9 m', weight: '120.0 kg', ability: 'Cabeza Roca', description: 'Sus cuernos perforan hasta diamantes. Puede caminar sobre lava sin quemarse. Es muy inteligente y protector. Su piel es más dura que el acero.', category: 'Pokémon Clavos', habitat: 'Montañas y terrenos rocosos', weaknesses: 'Agua, Planta, Hielo, Lucha, Tierra, Acero' },
  { id: 113, name: 'Chansey', type: 'Normal', height: '1.1 m', weight: '34.6 kg', ability: 'Gran Encanto', description: 'Corre tan rápido que es casi imposible atraparla. Su cuerpo almacena nutrición que comparte con los heridos. Pone huevos nutricionales diariamente. Es muy cariñosa y maternal.', category: 'Pokémon Huevo', habitat: 'Praderas y zonas urbanas', weaknesses: 'Lucha' },
  { id: 114, name: 'Tangela', type: 'Planta', height: '1.0 m', weight: '35.0 kg', ability: 'Clorofila', description: 'Vides azules que ocultan su verdadera forma. Sus vides nunca dejan de moverse. Puede atrapar presas con sus vides y absorber sus nutrientes. Es difícil ver su cuerpo real debajo de todas las vides.', category: 'Pokémon Enredadera', habitat: 'Bosques y praderas', weaknesses: 'Fuego, Hielo, Veneno, Volador, Bicho' },
  { id: 115, name: 'Kangaskhan', type: 'Normal', height: '2.2 m', weight: '80.0 kg', ability: 'Foco Interno', description: 'Siempre lleva a su cría en la bolsa marsupial. Protege ferozmente a sus crías. Puede dar golpes demoledores con sus puños. Su cría sale de la bolsa para aprender a pelear.', category: 'Pokémon Madre', habitat: 'Praderas y bosques', weaknesses: 'Lucha' },
  { id: 116, name: 'Horsea', type: 'Agua', height: '0.4 m', weight: '8.0 kg', ability: 'Nado Rápido', description: 'Nada hacia atrás usando su aleta dorsal. Dispara chorros de tinta para defenderse. Se agarra de coral para no ser arrastrado por la corriente. Es muy pequeño pero ágil.', category: 'Pokémon Caballito de Mar', habitat: 'Arrecifes de coral', weaknesses: 'Eléctrico, Planta' },
  { id: 117, name: 'Seadra', type: 'Agua', height: '1.2 m', weight: '25.0 kg', ability: 'Nado Rápido', description: 'Sus puntas dorsales son venenosas. Puede nadar hacia atrás muy rápido. Las puntas de sus aletas pueden inyectar veneno. Es muy territorial de su territorio acuático.', category: 'Pokémon Caballito de Mar', habitat: 'Arrecifes de coral', weaknesses: 'Eléctrico, Planta' },
  { id: 118, name: 'Goldeen', type: 'Agua', height: '0.6 m', weight: '15.0 kg', ability: 'Nado Rápido', description: 'Su elegante aleta parece un vestido. Nada con gracia en estanques y lagos. Sus aletas son muy fuertes a pesar de su apariencia delicada. Es popular por su belleza.', category: 'Pokémon Pez Dorado', habitat: 'Lagos y estanques', weaknesses: 'Eléctrico, Planta' },
  { id: 119, name: 'Seaking', type: 'Agua', height: '1.3 m', weight: '39.0 kg', ability: 'Nado Rápido', description: 'Los machos hacen nidos en el lecho de los ríos. Tiene un cuerno perforador en la cabeza. Es muy territorial durante la época de apareamiento. Protege ferozmente su territorio de cría.', category: 'Pokémon Pez Dorado', habitat: 'Lagos y estanques', weaknesses: 'Eléctrico, Planta' },
  { id: 120, name: 'Staryu', type: 'Agua', height: '0.8 m', weight: '34.5 kg', ability: 'Cura Natural', description: 'Su núcleo rojo brilla con siete colores. Puede regenerarse completamente si se le cortan los brazos. Es nocturno y brilla intensamente en la oscuridad. Su núcleo es su órgano vital.', category: 'Pokémon Estrella', habitat: 'Playas y aguas poco profundas', weaknesses: 'Eléctrico, Planta' },
  { id: 121, name: 'Starmie', type: 'Agua/Psíquico', height: '1.1 m', weight: '80.0 kg', ability: 'Cura Natural', description: 'Su núcleo brillante se llama la gema del mar. Puede nadar a gran velocidad girando como una estrella. Sus poderes psíquicos son muy desarrollados. Es extremadamente raro encontrarlo en estado salvaje.', category: 'Pokémon Misterioso', habitat: 'Océanos profundos', weaknesses: 'Eléctrico, Planta, Bicho, Fantasma, Siniestro' },
  { id: 122, name: 'Mr. Mime', type: 'Psíquico/Hada', height: '1.3 m', weight: '54.5 kg', ability: 'Insonorizar', description: 'Experto en mímica, crea barreras invisibles con sus manos. Puede crear paredes sólidas de aire. Es muy silencioso y se mueve con gracia. Vive principalmente en áreas urbanas.', category: 'Pokémon Barrera', habitat: 'Ciudades y zonas urbanas', weaknesses: 'Acero, Veneno, Fantasma, Siniestro' },
  { id: 123, name: 'Scyther', type: 'Bicho/Volador', height: '1.5 m', weight: '56.0 kg', ability: 'Enjambre', description: 'Sus guadañas cortan hierba con precisión quirúrgica. Puede moverse tan rápido que parece invisible. Sus alas le permiten volar a gran velocidad. Es un cazador muy habilidoso.', category: 'Pokémon Mantis', habitat: 'Praderas y zonas altas', weaknesses: 'Fuego, Volador, Roca, Eléctrico, Hielo' },
  { id: 124, name: 'Jynx', type: 'Hielo/Psíquico', height: '1.4 m', weight: '40.6 kg', ability: 'Despiste', description: 'Baila rítmicamente mientras camina. Su baile puede hipnotizar a quien lo mira. Su piel es extremadamente fría al tacto. Comunica sus emociones a través de movimientos gráciles.', category: 'Pokémon Humanimal', habitat: 'Cuevas frías y montañas heladas', weaknesses: 'Acero, Fuego, Roca, Bicho, Fantasma, Siniestro' },
  { id: 125, name: 'Electabuzz', type: 'Eléctrico', height: '1.1 m', weight: '30.0 kg', ability: 'Elec. Estática', description: 'Genera electricidad antes de tormentas. Su cuerpo brilla cuando está cargado de electricidad. Es muy territorial y protege fuentes de electricidad. Puede absorber electricidad de tormentas.', category: 'Pokémon Eléctrico', habitat: 'Centrales eléctricas y zonas de tormenta', weaknesses: 'Tierra' },
  { id: 126, name: 'Magmar', type: 'Fuego', height: '1.3 m', weight: '44.5 kg', ability: 'Cuerpo Llama', description: 'Su cuerpo arde a 2,200 grados Fahrenheit. Vive cerca de volcanes activos. Su cuerpo está cubierto de llamas constantemente. Puede lanzar bolas de fuego de su boca.', category: 'Pokémon Escupefuego', habitat: 'Volcanes y zonas volcánicas', weaknesses: 'Agua, Tierra, Roca' },
  { id: 127, name: 'Pinsir', type: 'Bicho', height: '1.5 m', weight: '55.0 kg', ability: 'Corte Fuerte', description: 'Sus pinzas pueden partir troncos en dos. Usa sus pinzas para levantar objetos pesados. Es muy territorial y agresivo. Sus pinzas son más fuertes que el acero.', category: 'Pokémon Escarabajo', habitat: 'Bosques y selvas tropicales', weaknesses: 'Fuego, Volador, Roca' },
  { id: 128, name: 'Tauros', type: 'Normal', height: '1.4 m', weight: '88.4 kg', ability: 'Intimidación', description: 'Carga violentamente cuando ve objetos rojos. Es muy territorial y protege su manada. Sus tres colas le dan equilibrio perfecto. Puede correr durante días sin cansarse.', category: 'Pokémon Toro Bravo', habitat: 'Praderas y llanuras', weaknesses: 'Lucha' },
  { id: 129, name: 'Magikarp', type: 'Agua', height: '0.9 m', weight: '10.0 kg', ability: 'Nado Rápido', description: 'El Pokémon más débil que apenas puede nadar. Solo puede saltar y salpicar agua. Pero tiene un potencial inmenso para evolucionar. Es conocido por su increíble capacidad de supervivencia.', category: 'Pokémon Pez', habitat: 'Lagos y ríos', weaknesses: 'Eléctrico, Planta' },
  { id: 130, name: 'Gyarados', type: 'Agua/Volador', height: '6.5 m', weight: '235.0 kg', ability: 'Intimidación', description: 'Extremadamente violento y destructivo. Evoluciona de Magikarp después de mucha perseverancia. Puede destruir ciudades enteras cuando está enfurecido. Su furia legendaria dura meses.', category: 'Pokémon Atrocidad', habitat: 'Lagos y océanos', weaknesses: 'Eléctrico, Roca' },
  { id: 131, name: 'Lapras', type: 'Agua/Hielo', height: '2.5 m', weight: '220.0 kg', ability: 'Sebo', description: 'Lleva a la gente sobre su caparazón. Puede nadar durante días sin descansar. Es muy inteligente y comprende el lenguaje humano. Es tranquilo y nunca pelea.', category: 'Pokémon Transporte', habitat: 'Océanos y mares', weaknesses: 'Eléctrico, Planta, Lucha' },
  { id: 132, name: 'Ditto', type: 'Normal', height: '0.3 m', weight: '4.0 kg', ability: 'Flexibilidad', description: 'Puede transformarse en cualquier cosa viva. Su transformación es perfecta pero mantiene su cara sonriente. Es útil para la cría de Pokémon. Su cuerpo es flexible como goma.', category: 'Pokémon Transformación', habitat: 'Cualquier lugar', weaknesses: 'Lucha' },
  { id: 133, name: 'Eevee', type: 'Normal', height: '0.3 m', weight: '6.5 kg', ability: 'Fuga', description: 'Su ADN irregular le permite evolucionar de múltiples formas. Es muy adaptable y puede vivir en cualquier ambiente. Es leal y cariñoso con su entrenador. Su pelaje es suave y cálido.', category: 'Pokémon Evolución', habitat: 'Ciudades y praderas', weaknesses: 'Lucha' },
  { id: 134, name: 'Vaporeon', type: 'Agua', height: '1.0 m', weight: '29.0 kg', ability: 'Absorbe Agua', description: 'Su estructura celular es similar al agua. Puede desaparecer en el agua completamente. Su cola se bifurca en dos y parece una aleta. Es excelente nadando y puede respirar bajo el agua.', category: 'Pokémon Burbuja', habitat: 'Lagos y océanos', weaknesses: 'Eléctrico, Planta' },
  { id: 135, name: 'Jolteon', type: 'Eléctrico', height: '0.8 m', weight: '24.5 kg', ability: 'Absorbe Elec', description: 'Las células de su cuerpo generan electricidad. Puede lanzar agujas eléctricas de su pelaje. Su pelaje se eriza cuando está emocionado. Es el Pokémon más rápido de las evoluciones de Eevee.', category: 'Pokémon Relámpago', habitat: 'Praderas y zonas eléctricas', weaknesses: 'Tierra' },
  { id: 136, name: 'Flareon', type: 'Fuego', height: '0.9 m', weight: '25.0 kg', ability: 'Absorbe Fuego', description: 'Almacena llamas en el saco de su piel. Su pelaje es muy cálido y perfecto para climas fríos. Puede alcanzar temperaturas de 900 grados. Es el más fuerte físicamente de las evoluciones de Eevee.', category: 'Pokémon Llama', habitat: 'Praderas y volcanes', weaknesses: 'Agua, Tierra, Roca' },
  { id: 137, name: 'Porygon', type: 'Normal', height: '0.8 m', weight: '36.5 kg', ability: 'Rastreo', description: 'Primer Pokémon creado por computadora. Puede viajar por el ciberespacio. No necesita comer, dormir ni respirar. Es muy inteligente pero a veces tiene errores de software.', category: 'Pokémon Virtual', habitat: 'Ciberespacio y ciudades', weaknesses: 'Lucha' },
  { id: 138, name: 'Omanyte', type: 'Roca/Agua', height: '0.4 m', weight: '7.5 kg', ability: 'Nado Rápido', description: 'Pokémon extinto que revive desde un fósil. Usaba sus tentáculos para nadar y capturar presas. Su caparazón lo protegía de depredadores. Es un Pokémon prehistórico muy antiguo.', category: 'Pokémon Espiral', habitat: 'Océanos prehistóricos', weaknesses: 'Planta, Eléctrico, Lucha, Tierra' },
  { id: 139, name: 'Omastar', type: 'Roca/Agua', height: '1.0 m', weight: '35.0 kg', ability: 'Nado Rápido', description: 'Sus tentáculos se hicieron más fuertes al evolucionar. Su caparazón es más grande y pesado. Podía aplastar presas con sus tentáculos. Se extinguió porque su caparazón era demasiado pesado.', category: 'Pokémon Espiral', habitat: 'Océanos prehistóricos', weaknesses: 'Planta, Eléctrico, Lucha, Tierra' },
  { id: 140, name: 'Kabuto', type: 'Roca/Agua', height: '0.5 m', weight: '11.5 kg', ability: 'Nado Rápido', description: 'Se protege con su caparazón endurecido. Es un Pokémon fósil de 300 millones de años. Sus ojos pueden ver en la oscuridad total. Puede nadar rápidamente pese a su caparazón.', category: 'Pokémon Caparazón', habitat: 'Océanos prehistóricos', weaknesses: 'Planta, Eléctrico, Lucha, Tierra' },
  { id: 141, name: 'Kabutops', type: 'Roca/Agua', height: '1.3 m', weight: '40.5 kg', ability: 'Nado Rápido', description: 'Cazador que nadaba rápidamente para atrapar presas. Sus garras afiladas pueden cortar rocas. Es un Pokémon fósil muy agresivo. Puede caminar sobre dos patas fuera del agua.', category: 'Pokémon Caparazón', habitat: 'Océanos prehistóricos', weaknesses: 'Planta, Eléctrico, Lucha, Tierra' },
  { id: 142, name: 'Aerodactyl', type: 'Roca/Volador', height: '1.8 m', weight: '59.0 kg', ability: 'Cabeza Roca', description: 'Pokémon prehistórico que domina los cielos. Revive desde un fósil de ámbar. Su rugido puede asustar a cualquier enemigo. Era el depredador aéreo más temido de la era prehistórica.', category: 'Pokémon Fósil', habitat: 'Montañas y cielos prehistóricos', weaknesses: 'Agua, Planta, Hielo, Roca, Acero, Eléctrico' },
  { id: 143, name: 'Snorlax', type: 'Normal', height: '2.1 m', weight: '460.0 kg', ability: 'Sebo', description: 'Come hasta 400 kg de comida y luego duerme. Es muy difícil de despertar una vez que se duerme. Su estómago puede digerir cualquier cosa, incluso comida mohosa. Es muy tranquilo cuando no está comiendo.', category: 'Pokémon Dormilón', habitat: 'Montañas y bosques', weaknesses: 'Lucha' },
  { id: 144, name: 'Articuno', type: 'Hielo/Volador', height: '1.7 m', weight: '55.4 kg', ability: 'Presión', description: 'Ave legendaria que controla el hielo. Su vuelo congela el aire a su paso. Aparece ante los entrenadores perdidos en montañas heladas. Su belleza es legendaria y conmovedora.', category: 'Pokémon Congelar', habitat: 'Montañas heladas y cuevas de hielo', weaknesses: 'Fuego, Eléctrico, Roca, Acero' },
  { id: 145, name: 'Zapdos', type: 'Eléctrico/Volador', height: '1.6 m', weight: '52.6 kg', ability: 'Presión', description: 'Ave legendaria que controla el trueno. Vive en nubes de tormenta y genera electricidad. Su vuelo crea truenos ensordecedores. Es uno de los Pokémon legendarios más poderosos.', category: 'Pokémon Eléctrico', habitat: 'Nubes de tormenta y centrales eléctricas', weaknesses: 'Hielo, Roca' },
  { id: 146, name: 'Moltres', type: 'Fuego/Volador', height: '2.0 m', weight: '60.0 kg', ability: 'Presión', description: 'Ave legendaria que controla el fuego. Su vuelo deja un rastro de llamas ardientes. Cuenta la leyenda que trae la primavera donde pasa. Es tan majestuoso como peligroso.', category: 'Pokémon Llama', habitat: 'Volcanes activos y zonas volcánicas', weaknesses: 'Agua, Eléctrico, Roca' },
  { id: 147, name: 'Dratini', type: 'Dragón', height: '1.8 m', weight: '3.3 kg', ability: 'Mudar', description: 'Dragón mítico que vive en profundos lagos. Es muy raro y difícil de avistar. Su cuerpo serpentino es muy elástico. Cuenta la leyenda que crece enormemente al evolucionar.', category: 'Pokément Dragón', habitat: 'Lagos profundos y cuevas acuáticas', weaknesses: 'Hielo, Dragón, Hada' },
  { id: 148, name: 'Dragonair', type: 'Dragón', height: '4.0 m', weight: '16.5 kg', ability: 'Mudar', description: 'Controla el clima con cristales en su cuello. Su cuerpo emite una aura misteriosa. Puede volar a pesar de no tener alas. Es un Pokémon de naturaleza serena y majestuosa.', category: 'Pokémon Dragón', habitat: 'Lagos sagrados y cuevas místicas', weaknesses: 'Hielo, Dragón, Hada' },
  { id: 149, name: 'Dragonite', type: 'Dragón/Volador', height: '2.2 m', weight: '210.0 kg', ability: 'Foco Interno', description: 'Dragón amable que salva náufragos. Puede volar a 2,000 km/h. Es muy inteligente y comprensivo. A pesar de su tamaño, es muy gentil y protector de humanos.', category: 'Pokémon Dragón', habitat: 'Océanos y mares', weaknesses: 'Hielo, Dragón, Hada, Roca' },
  { id: 150, name: 'Mewtwo', type: 'Psíquico', height: '2.0 m', weight: '122.0 kg', ability: 'Presión', description: 'Creado por manipulación genética de Mew. Es el Pokémon más poderoso. Su inteligencia supera a la de los humanos. Busca comprender su propósito de existencia.', category: 'Pokémon Genético', habitat: 'Cavernas secretas y laboratorios', weaknesses: 'Bicho, Fantasma, Siniestro' },
  { id: 151, name: 'Mew', type: 'Psíquico', height: '0.4 m', weight: '4.0 kg', ability: 'Sincronía', description: 'Se dice que contiene el código genético de todos los Pokémon. Puede hacerse invisible a voluntad y rara vez muestra su forma. Es tan raro que muchos expertos creen que es un mito. Tiene habilidades de todas las especies.', category: 'Pokémon Nueva Especie', habitat: 'Lugares desconocidos y secretos', weaknesses: 'Bicho, Fantasma, Siniestro' }
]

export const getPokemonById = (id) => pokemonData.find(p => p.id === id)
export const getPokemonByType = (type) => pokemonData.filter(p => p.type.includes(type))
